def _load_photo(b64_str):
    try:
        data = base64.b64decode(b64_str)
        if _PIL:
            img = Image.open(BytesIO(data))
            return ImageTk.PhotoImage(img)
        else:
            return tk.PhotoImage(data=b64_str)
    except Exception:
        return None

