# ── Konfiguration ─────────────────────────────────────────────────────────────
def load_config() -> dict:
    if os.path.exists(CONFIG_FILE):
        try:
            with open(CONFIG_FILE, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {}

def save_config(cfg: dict):
    try:
        with open(CONFIG_FILE, "w", encoding="utf-8") as f:
            json.dump(cfg, f, ensure_ascii=False, indent=2)
    except Exception as e:
        messagebox.showwarning("Konfiguration", f"Einstellungen konnten nicht gespeichert werden:\n{e}")

# ── Hilfsfunktionen ───────────────────────────────────────────────────────────
def human_size(b):
    for u in ["B", "KB", "MB", "GB", "TB"]:
        if b < 1024.0:
            return f"{b:.1f} {u}"
        b /= 1024.0
    return f"{b:.1f} PB"

def format_date(filepath):
    from datetime import datetime
    return datetime.fromtimestamp(os.path.getmtime(filepath)).strftime("%d.%m.%Y %H:%M")

def find_backups(cfg: dict) -> list:
    target = cfg.get("backup_target", "")
    local  = sorted(glob.glob(os.path.join(SCRIPT_DIR, "TUX_FULL_BACKUP_*.tar.gz")),
                    key=os.path.getmtime, reverse=True)
    if local:
        return local
    if target:
        return sorted(glob.glob(os.path.join(target, "TUX_FULL_BACKUP_*.tar.gz")),
                      key=os.path.getmtime, reverse=True)
    return []

def is_target_accessible(cfg: dict) -> bool:
    target = cfg.get("backup_target", "")
    return bool(target) and os.path.isdir(target)

def apply_styles():
    style = ttk.Style()
    style.theme_use("clam")
    style.configure("TNotebook",     background=BG,      borderwidth=0)
    style.configure("TNotebook.Tab", background=SURFACE, foreground=TEXT,
                    padding=[16, 7], font=("Arial", 11))
    style.map("TNotebook.Tab",
              background=[("selected", BLUE)],
              foreground=[("selected", CRUST)])
    style.configure("Treeview",
                    background=SURFACE, fieldbackground=SURFACE,
                    foreground=TEXT, rowheight=26, font=("Arial", 10))
    style.configure("Treeview.Heading",
                    background=OVERLAY, foreground=TEXT, font=("Arial", 10, "bold"))
    style.map("Treeview", background=[("selected", OVERLAY)])
    style.configure("TProgressbar", troughcolor=SURFACE, background=GREEN)

