    # ── Tab 2: Wiederherstellen ───────────────────────────────────────────────
    def _build_restore_tab(self, parent):
        tk.Label(parent, text="Schritt 1 – Welches Backup?",
                 font=("Arial", 12, "bold"), fg=BLUE, bg=BG
                 ).pack(anchor=tk.W, padx=20, pady=(14, 4))

        list_frame = tk.Frame(parent, bg=SURFACE)
        list_frame.pack(fill=tk.X, padx=20, pady=(0, 6))

        backups = find_backups(self._cfg)
        self._restore_backup_var = tk.StringVar()

        if not backups:
            tk.Label(list_frame,
                     text="Keine Backup-Dateien gefunden!\nBitte zuerst ein Backup erstellen oder Zielordner pruefen.",
                     fg=RED, bg=SURFACE, font=("Arial", 11), pady=10).pack()
        else:
            for i, bp in enumerate(backups):
                size = human_size(os.path.getsize(bp))
                date = format_date(bp)
                sha  = "Pruefung OK" if os.path.exists(bp + ".sha256") else "keine Pruefung"
                rb = tk.Radiobutton(
                    list_frame,
                    text=f"  {date}  –  {size}  –  {sha}",
                    variable=self._restore_backup_var, value=bp,
                    font=("Arial", 10), fg=TEXT, bg=SURFACE,
                    selectcolor=OVERLAY, activebackground=SURFACE,
                    pady=6, padx=12,
                )
                rb.pack(anchor=tk.W)
                if i == 0:
                    self._restore_backup_var.set(bp)

        tk.Label(parent, text="Schritt 2 – Wohin sollen die Dateien?",
                 font=("Arial", 12, "bold"), fg=BLUE, bg=BG
                 ).pack(anchor=tk.W, padx=20, pady=(12, 4))

        tf = tk.Frame(parent, bg=BG)
        tf.pack(fill=tk.X, padx=20)
        self._restore_target_var = tk.StringVar(value=os.path.join(
            os.path.expanduser("~"), "Desktop", "TUXPLAYER_Wiederherstellung"
        ))
        tk.Entry(tf, textvariable=self._restore_target_var,
                 font=("Arial", 10), fg=TEXT, bg=OVERLAY,
                 relief=tk.FLAT, insertbackground=TEXT,
                 ).pack(side=tk.LEFT, fill=tk.X, expand=True, ipady=6, padx=(0, 6))
        tk.Button(tf, text="Ordner waehlen ...",
                  command=self._restore_choose_target,
                  font=("Arial", 10), fg=BG, bg=BLUE,
                  relief=tk.FLAT, padx=10, pady=5, cursor="hand2",
                  ).pack(side=tk.LEFT)

        self._restore_status = tk.Label(parent, text="",
                                        font=("Arial", 10), fg=GREEN, bg=BG)
        self._restore_status.pack(pady=(12, 2))
        self._restore_progress = ttk.Progressbar(parent, maximum=100,
                                                  length=500, mode="indeterminate")
        self._restore_progress.pack(pady=(0, 8))
        self._restore_btn = tk.Button(
            parent,
            text="Schritt 3 – Dateien jetzt wiederherstellen",
            command=self._restore_start,
            font=("Arial", 13, "bold"), fg=BG, bg=GREEN,
            relief=tk.FLAT, padx=20, pady=14, cursor="hand2",
        )
        self._restore_btn.pack(pady=8)
        if self._img_mascot:
            tk.Label(parent, image=self._img_mascot, bg=BG).pack(pady=(4, 12))

    def _restore_choose_target(self):
        folder = filedialog.askdirectory(title="Zielordner waehlen")
        if folder:
            self._restore_target_var.set(folder)

    def _restore_start(self):
        backup = self._restore_backup_var.get()
        target = self._restore_target_var.get().strip()
        if not backup or not os.path.exists(backup):
            messagebox.showerror("Fehler", "Bitte erst ein Backup auswaehlen."); return
        if not target:
            messagebox.showerror("Fehler", "Bitte einen Zielordner angeben."); return
        if not messagebox.askyesno("Bestaetigung",
            f"Backup:\n{os.path.basename(backup)}\n\nZiel:\n{target}\n\n"
            "Dateien jetzt wiederherstellen?\n(Kann 30 Minuten bis mehrere Stunden dauern!)"
        ): return
        self._restore_btn.config(state=tk.DISABLED)
        self._restore_progress.config(mode="indeterminate")
        self._restore_progress.start(10)
        self._restore_status.config(text="Laeuft ... bitte warten. Dieses Fenster nicht schliessen!")
        threading.Thread(target=self._restore_run, args=(backup, target), daemon=True).start()

    def _restore_run(self, backup, target):
        try:
            os.makedirs(target, exist_ok=True)
            with tarfile.open(backup, "r:gz") as tar:
                members = []
                for m in tar.getmembers():
                    parts = m.name.split("/", 2)
                    if len(parts) >= 3 and parts[2]:
                        m.name = parts[2]; members.append(m)
                    elif len(parts) == 2 and parts[1]:
                        m.name = parts[1]; members.append(m)
                try:
                    tar.extractall(target, members=members, filter="fully_trusted")
                except TypeError:
                    tar.extractall(target, members=members)
            self.root.after(0, self._restore_done, target)
        except Exception as e:
            self.root.after(0, self._restore_error, str(e))

    def _restore_done(self, target):
        self._restore_progress.stop()
        self._restore_progress.config(mode="determinate")
        self._restore_progress["value"] = 100
        self._restore_status.config(text="Fertig!")
        self._restore_btn.config(state=tk.NORMAL)
        messagebox.showinfo("Fertig!",
            f"Alle Dateien wurden erfolgreich wiederhergestellt!\n\nDu findest sie unter:\n{target}")

    def _restore_error(self, error):
        self._restore_progress.stop()
        self._restore_status.config(text="Fehler aufgetreten.")
        self._restore_btn.config(state=tk.NORMAL)
        messagebox.showerror("Fehler",
            f"Etwas ist schiefgelaufen:\n\n{error}\n\n"
            "Bitte jemanden fragen der sich mit Computern auskennt.")

    # ── Tab 3: Backup-Steuerung ────────────────────────────────────────────────
    def _choose_backup_target(self):
        folder = filedialog.askdirectory(title="Backup-Zielordner waehlen (z.B. externe Festplatte)")
        if folder:
            self._cfg["backup_target"] = folder
            save_config(self._cfg)
            self._backup_refresh_status()
            messagebox.showinfo("Ziel gespeichert",
                f"Backup-Ziel gesetzt auf:\n{folder}\n\nDie Einstellung wird dauerhaft gespeichert.")

